using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpHttpServer.Tools;

[McpServerToolType]
public static class WeatherTool
{
    [McpServerTool, Description("Gets the current weather for a given city.")]
    public static string GetWeather(
        [Description("The city name to get weather for")] string city)
    {
        // In production, call a real weather API
        return $"The weather in {city} is 72°F and sunny.";
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

namespace McpHttpServer.Resources;

[McpServerResourceType]
public static class ConfigResource
{
    [McpServerResource(
        Uri = "config://app/settings",
        Name = "Application Settings",
        Description = "Returns the current application configuration data.",
        MimeType = "application/json")]
    public static string GetAppSettings()
    {
        var config = new
        {
            AppName = "McpHttpServer",
            Version = "1.0.0",
            Environment = "Development",
            Features = new { EnableCaching = true, MaxRetries = 3 }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        Uri = "config://app/endpoints",
        Name = "API Endpoints",
        Description = "Returns the list of available API endpoints.",
        MimeType = "application/json")]
    public static string GetEndpoints()
    {
        var endpoints = new[]
        {
            new { Path = "/mcp", Method = "POST", Description = "MCP server endpoint" },
            new { Path = "/mcp/sse", Method = "GET", Description = "MCP SSE transport" }
        };

        return JsonSerializer.Serialize(endpoints, new JsonSerializerOptions { WriteIndented = true });
    }
}

